    echo '{"sockname":"/tmp/fake-watchman-sock"}'
    exit 0
elif [ "$1" = "watch-project" ]; then
    echo '{"watch":"/tmp","relative_path":""}'
    exit 0
elif [ "$1" = "version" ]; then
    echo '{"version":"5.0.0"}'
    exit 0
fi
exit 0
